<?php
namespace App\Domain\WorldMaps;use App\Models\WorldMap;use App\Models\WorldMapArea;use Illuminate\Support\Facades\Route;use InvalidArgumentException;
final class WorldMapAreaActionValidator{private $maps;private $resolver;public function __construct(WorldMapValidator $maps,WorldMapResolver $resolver){$this->maps=$maps;$this->resolver=$resolver;}public function validate(WorldMapArea $area,WorldMap $parent,$strict=true){if(!in_array($area->status,WorldMapAreaStatus::values(),true))throw new InvalidArgumentException('Invalid area status.');if(!in_array($area->action_type,WorldMapActionType::all(),true))throw new InvalidArgumentException('Invalid WorldMap action type.');if(in_array($area->action_type,WorldMapActionType::reserved(),true)){if($strict||$area->status===WorldMapAreaStatus::ACTIVE)throw new InvalidArgumentException('This action type is reserved and cannot be activated.');return;}if($area->available_from&&$area->available_until&&$area->available_from->gt($area->available_until))throw new InvalidArgumentException('Availability start must not exceed its end.');if(!$strict&&$area->status===WorldMapAreaStatus::DRAFT)return;$fields=['zone_id','target_world_map_id','target_world_id','target_region_id','internal_route_name'];$required=['zone'=>'zone_id','map'=>'target_world_map_id','world'=>'target_world_id','region'=>'target_region_id','internal_route'=>'internal_route_name'];foreach($fields as $field){$must=isset($required[$area->action_type])&&$required[$area->action_type]===$field;if($must&&!$area->{$field})throw new InvalidArgumentException('Configured action is missing its required target.');if(!$must&&$area->{$field})throw new InvalidArgumentException('Configured action contains an incompatible target.');}if($area->action_type===WorldMapActionType::INFO&&trim((string)$area->description)==='')throw new InvalidArgumentException('Information areas require a plain-text description.');if($area->action_type===WorldMapActionType::MAP){if((int)$area->target_world_map_id===(int)$parent->id)throw new InvalidArgumentException('A map area cannot target its own WorldMap.');$target=$area->targetWorldMap;if(!$target)throw new InvalidArgumentException('Target WorldMap does not exist.');if($area->status===WorldMapAreaStatus::ACTIVE){$this->maps->validate($target);if($target->status!==WorldMapStatus::ACTIVE)throw new InvalidArgumentException('Active map action requires an active target.');}}if($area->action_type===WorldMapActionType::WORLD){if(!$area->targetWorld||$area->targetWorld->status!=='active')throw new InvalidArgumentException('World target is not active.');try{$this->resolver->forWorld($area->targetWorld);}catch(\Throwable $e){throw new InvalidArgumentException('World target has no active default map.');}}if($area->action_type===WorldMapActionType::REGION){if(!$area->targetRegion||$area->targetRegion->status!=='active')throw new InvalidArgumentException('Region target is not active.');try{$this->resolver->forRegion($area->targetRegion);}catch(\Throwable $e){throw new InvalidArgumentException('Region target has no active default map.');}}if($area->action_type===WorldMapActionType::ZONE&&(!$area->zone||$area->zone->status!=='active'))throw new InvalidArgumentException('Zone target is not active.');if($area->action_type===WorldMapActionType::INTERNAL_ROUTE)$this->validateInternalRoute($area);}private function validateInternalRoute(WorldMapArea $area){$routes=config('world_maps.internal_routes',[]);if(!isset($routes[$area->internal_route_name]))throw new InvalidArgumentException('Internal route is not allowlisted.');$route=$routes[$area->internal_route_name];if(!Route::has($route['route_name']))throw new InvalidArgumentException('Allowlisted internal route does not exist.');$parameters=$area->internal_route_parameters?:[];if(!is_array($parameters))throw new InvalidArgumentException('Invalid internal route parameters.');$allowed=isset($route['allowed_parameters'])?$route['allowed_parameters']:[];foreach($parameters as $key=>$value){if(!in_array($key,$allowed,true)||!is_scalar($value)||in_array($key,isset($route['authoritative_parameters'])?$route['authoritative_parameters']:[],true))throw new InvalidArgumentException('Internal route contains forbidden parameters.');}}}
